149	// loadWorkersConfig reads .ddx/config.yaml at projectRoot and returns the
150	// workers block, or nil when unset / on error. Errors are swallowed because
151	// a missing or malformed config must not block the dispatch path.
152	func loadWorkersConfig(projectRoot string) *config.WorkersConfig {
153		if projectRoot == "" {
154			return nil
155		}
156		cfg, err := config.LoadWithWorkingDir(projectRoot)
157		if err != nil || cfg == nil {
158			return nil
159		}
160		return cfg.Workers
161	}
