package server

import (
	"context"
	"os"
	"path/filepath"
	"testing"
	"time"

	"github.com/DocumentDrivenDX/ddx/internal/agent"
)

// TestDispatchWorkerDefaultsProfileToDefault verifies AC#1 of ddx-755f5881:
// workerDispatchAdapter.DispatchWorker called with empty rawArgs produces a
// spec with Profile="default" and no other routing fields populated.
//
// The fix ensures `ddx work` / `ddx agent execute-loop` and the GraphQL
// "+ Add worker" path both flow into the single-ResolveRoute(Profile) default
// path rather than falling through to per-tier iteration.
func TestDispatchWorkerDefaultsProfileToDefault(t *testing.T) {
	root := t.TempDir()
	setupBeadStore(t, root)

	m := NewWorkerManager(root)
	defer m.StopWatchdog()

	// No-op factory: records the dispatch and exits cleanly without doing
	// any real work so we can inspect the resulting WorkerRecord.
	m.BeadWorkerFactory = func(s agent.ExecuteBeadLoopStore) *agent.ExecuteBeadWorker {
		return &agent.ExecuteBeadWorker{
			Store: s,
			Executor: agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
				return agent.ExecuteBeadReport{BeadID: beadID, Status: agent.ExecuteBeadStatusNoChanges}, nil
			}),
		}
	}

	adapter := &workerDispatchAdapter{manager: m}
	result, err := adapter.DispatchWorker(context.Background(), "execute-loop", root, nil)
	if err != nil {
		t.Fatalf("DispatchWorker: %v", err)
	}
	defer func() { _ = m.Stop(result.ID) }()

	rec, err := m.Show(result.ID)
	if err != nil {
		t.Fatalf("show: %v", err)
	}
	if rec.Profile != "default" {
		t.Errorf("default DispatchWorker should set Profile=\"default\", got %q", rec.Profile)
	}
	if rec.Harness != "" {
		t.Errorf("default DispatchWorker should leave Harness empty, got %q", rec.Harness)
	}
	if rec.Model != "" {
		t.Errorf("default DispatchWorker should leave Model empty, got %q", rec.Model)
	}
	if rec.Provider != "" {
		t.Errorf("default DispatchWorker should leave Provider empty, got %q", rec.Provider)
	}
}

// TestDispatchWorkerEscalateOff verifies the dispatched spec defaults
// Escalate=false so the worker uses the single-ResolveRoute path. Asserted
// indirectly: the worker record reflects the spec that was passed.
func TestDispatchWorkerEscalateOff(t *testing.T) {
	root := t.TempDir()
	setupBeadStore(t, root)

	// Marker file so we can confirm the test ran past dispatch even when the
	// fake worker exits immediately.
	_ = os.WriteFile(filepath.Join(root, ".ddx", "_marker"), []byte("x"), 0o644)

	m := NewWorkerManager(root)
	defer m.StopWatchdog()
	m.BeadWorkerFactory = func(s agent.ExecuteBeadLoopStore) *agent.ExecuteBeadWorker {
		return &agent.ExecuteBeadWorker{
			Store: s,
			Executor: agent.ExecuteBeadExecutorFunc(func(ctx context.Context, beadID string) (agent.ExecuteBeadReport, error) {
				<-ctx.Done()
				return agent.ExecuteBeadReport{BeadID: beadID, Status: agent.ExecuteBeadStatusExecutionFailed}, ctx.Err()
			}),
		}
	}

	adapter := &workerDispatchAdapter{manager: m}
	result, err := adapter.DispatchWorker(context.Background(), "execute-loop", root, nil)
	if err != nil {
		t.Fatalf("DispatchWorker: %v", err)
	}
	defer func() { _ = m.Stop(result.ID) }()

	// Give StartExecuteLoop a moment to write the initial record.
	time.Sleep(50 * time.Millisecond)

	if result.State == "" {
		t.Fatal("dispatch should produce a worker with a non-empty state")
	}
}

