package agent

import (
	"context"
	"errors"
	"testing"

	agentlib "github.com/DocumentDrivenDX/agent"
)

// routeCountingAgent is a DdxAgent stub that counts ResolveRoute calls and
// captures the most recent RouteRequest. Used to verify the default routing
// path of FEAT-006 (ddx-755f5881): ResolveRoute is invoked exactly once with
// only Profile populated; no Model/Harness/Provider sneak through.
type routeCountingAgent struct {
	catalogStubAgent
	calls   int
	lastReq agentlib.RouteRequest
	dec     *agentlib.RouteDecision
	err     error
}

func (s *routeCountingAgent) ResolveRoute(_ context.Context, req agentlib.RouteRequest) (*agentlib.RouteDecision, error) {
	s.calls++
	s.lastReq = req
	return s.dec, s.err
}

// TestResolveDefaultRouteCallsOnceWithProfileOnly verifies AC#2/AC#3 of
// ddx-755f5881: the default path issues a single ResolveRoute call with
// Profile populated and Model/Harness/Provider zero, and the helper does not
// call into ResolveProfileLadder or ResolveTierModelRef.
func TestResolveDefaultRouteCallsOnceWithProfileOnly(t *testing.T) {
	stub := &routeCountingAgent{
		dec: &agentlib.RouteDecision{Harness: "agent", Provider: "fake", Model: "fake-model"},
	}

	dec, err := ResolveDefaultRoute(context.Background(), stub, "")
	if err != nil {
		t.Fatalf("ResolveDefaultRoute: %v", err)
	}
	if stub.calls != 1 {
		t.Errorf("ResolveRoute calls: want 1, got %d", stub.calls)
	}
	if stub.lastReq.Profile != "default" {
		t.Errorf("ResolveRoute Profile: want \"default\" (normalized from empty), got %q", stub.lastReq.Profile)
	}
	if stub.lastReq.Model != "" {
		t.Errorf("ResolveRoute Model must be empty on default path, got %q", stub.lastReq.Model)
	}
	if stub.lastReq.Provider != "" {
		t.Errorf("ResolveRoute Provider must be empty on default path, got %q", stub.lastReq.Provider)
	}
	if stub.lastReq.ModelRef != "" {
		t.Errorf("ResolveRoute ModelRef must be empty on default path, got %q", stub.lastReq.ModelRef)
	}
	if dec.Harness != "agent" {
		t.Errorf("decision harness pass-through: want agent, got %q", dec.Harness)
	}
}

// TestResolveDefaultRouteNamedProfile verifies the helper still threads a
// caller-supplied profile through without modification.
func TestResolveDefaultRouteNamedProfile(t *testing.T) {
	stub := &routeCountingAgent{
		dec: &agentlib.RouteDecision{Harness: "agent"},
	}
	if _, err := ResolveDefaultRoute(context.Background(), stub, "smart"); err != nil {
		t.Fatalf("ResolveDefaultRoute: %v", err)
	}
	if stub.lastReq.Profile != "smart" {
		t.Errorf("Profile should pass through unchanged, got %q", stub.lastReq.Profile)
	}
}

// TestResolveDefaultRoutePropagatesError verifies AC#4 of ddx-755f5881: when
// the upstream engine returns "no viable provider", the default path returns
// a single typed error rather than retrying. This is the single-error
// regression coverage for the historical 19-burn drain-queue failure.
func TestResolveDefaultRoutePropagatesError(t *testing.T) {
	want := errors.New("no viable provider")
	stub := &routeCountingAgent{err: want}

	_, err := ResolveDefaultRoute(context.Background(), stub, "default")
	if err == nil {
		t.Fatal("expected error, got nil")
	}
	if !errors.Is(err, want) {
		t.Errorf("error pass-through: want %v, got %v", want, err)
	}
	if stub.calls != 1 {
		t.Errorf("default path must NOT retry; ResolveRoute calls: want 1, got %d", stub.calls)
	}
}

package cmd

import (
	"strings"
	"testing"

	"github.com/stretchr/testify/assert"
	"github.com/stretchr/testify/require"
)

// TestExecuteLoopEscalateFlagRegistered verifies AC#5 of ddx-755f5881:
// --escalate is a recognized flag on `ddx agent execute-loop`. Tier-ladder
// machinery (cheap → standard → smart) is preserved as opt-in via this flag
// even though the default path no longer iterates.
func TestExecuteLoopEscalateFlagRegistered(t *testing.T) {
	t.Setenv("DDX_DISABLE_UPDATE_CHECK", "1")

	dir := t.TempDir()
	rootCmd := NewCommandFactory(dir).NewRootCommand()
	output, err := executeCommand(rootCmd, "agent", "execute-loop", "--help")
	require.NoError(t, err)
	assert.Contains(t, output, "--escalate", "tier-ladder routing must remain reachable via --escalate")
}

// TestWorkEscalateFlagRegistered verifies the same flag is available on the
// `ddx work` alias since it shares execute-loop's flag set.
func TestWorkEscalateFlagRegistered(t *testing.T) {
	t.Setenv("DDX_DISABLE_UPDATE_CHECK", "1")

	dir := t.TempDir()
	rootCmd := NewCommandFactory(dir).NewRootCommand()
	output, err := executeCommand(rootCmd, "work", "--help")
	require.NoError(t, err)
	assert.Contains(t, output, "--escalate")
}

// TestExecuteLoopMinTierFlagStillRegistered guards the regression: --min-tier
// / --max-tier remain available as part of the (opt-in) tier-ladder machinery.
func TestExecuteLoopMinTierFlagStillRegistered(t *testing.T) {
	t.Setenv("DDX_DISABLE_UPDATE_CHECK", "1")

	dir := t.TempDir()
	rootCmd := NewCommandFactory(dir).NewRootCommand()
	output, err := executeCommand(rootCmd, "agent", "execute-loop", "--help")
	require.NoError(t, err)
	for _, want := range []string{"--min-tier", "--max-tier"} {
		if !strings.Contains(output, want) {
			t.Errorf("execute-loop --help should advertise %s", want)
		}
	}
}

